```
#include <cctype>
#include <string>

bool isPalindrome(std::string s) {
    std::string cleanStr = "";
    // Конвертирајте во мали букви и отстранете ги неалфанумеричките знаци
    за (charc : s) {
        ако (std::isalnum(c)) {
            cleanStr += std::tolower(c);
        }
    }
    // Проверете дали е палиндром
    int лево = 0, десно = cleanStr.size() - 1;
    додека (лево <= десно) {
        if (cleanStr[лево++] != cleanStr[десно--])
            врати лажни;
    }
    врати вистина;
}
```
